INSERT INTO `modules` (`id`, `number`, `title`, `description`, `content`, `image_url`, `progress`, `completed`, `created_at`, `updated_at`) VALUES
('modulo-1',	1,	'Modulo 1',	'Fundamentos de la planificación arquitectónica y diseño estructural para proyectos Tilt-Up. Aprende a crear planos técnicos y calcular especificaciones.',	'1. Introducción\r\n1.1   ¿Qué es Tilt Up?\r\n1.2   Ventajas \r\n1.3   Proceso\r\n2. Materiales\r\n2.1   Concreto\r\n  2.1.1  Cemento/Material cementante\r\n  2.1.2  Agua\r\n  2.1.3  Aire Atrapado\r\n  2.1.4  Agregados \r\n  2.1.5  Aditivos\r\n  2.1.6  Revenimiento\r\n  2.1.7  Especificación\r\n  2.1.8  Resistencia\r\n2.2   Refuerzo\r\n  2.2.1  Refuerzo de barra de acero\r\n  2.2.2  Malla de refuerzo soldado\r\n  2.2.3  Soporte para barras de acero \r\n2.3   Encofrado\r\n2.4   Químicos para quitar el adhesivo\r\n2.5   Aislamiento\r\n2.3   Ladrillo\r\n3. Protección del material y seguridad\r\n3.1   Curado de concreto\r\n  3.1.1 Métodos de curado\r\n3.2   contracción conctrolada\r\n3.2   Precauciones en tiempo caluroso\r\n3.3   Precauciones en tiempo frio \r\n4. Planificación\r\n4.1   Diseño\r\n4.2   Preconstrucción\r\n  4.2.1  Manual de montaje\r\n  4.2.2  Planos de taller de los paneles\r\n4.3   Consideraciones estructurales\r\n4.4   Modular el edificio\r\n  4.4.1  Tamaño y formas de los paneles\r\n  4.4.2  Paneles fuera de los paneles\r\n4.5   Proceso de secuencia y disposición de los paneles\r\n  4.5.1  Disposición del espacio de colado\r\n  4.5.2  Acerca de las grúas\r\n  4.5.3  Posicionamiento de las grúas\r\n  4.5.4  Tipos y capacidades de grúas \r\n  4.5.5  Selección de la grúa\r\n4.6   Detalles del diseño\r\n  4.6.1  Acabados de la superficie\r\n  4.6.2  Clasificaciones de la resistencia a incendios\r\n  4.6.3  Desempeño térmico de los paneles de muro \r\n  4.6.4  Métodos de aislamiento\r\n',	'https://grabador.imcyc.com/Imagenes/generated_images/Planning_and_design_module_a2d487e6.png',	0,	0,	'2025-11-06 15:04:29',	'2026-02-13 16:57:56'),
('modulo-2',	2,	'Modulo 2',	'Técnicas de preparación del terreno, construcción de cimientos y losas de concreto. Incluye instalación de acero de refuerzo y procesos de vaciado.',	'1. LA LOSA DE PISO\r\n1.1   Losas de piso para tilt up\r\n  1.1.1 Diseño\r\n  1.1.2 Espesor\r\n  1.1.3 Cargas de construcciones temporales\r\n  1.1.4 Consideraciones para la carga de las riostras\r\n1.2   Refuerzo en las losas \r\n  1.2.1 Formula de la teoría de arrastre de la subrasante\r\n  1.2.2 Tipos de refuerzo\r\n  1.2.3 Tipos de juntas\r\n  1.2.4 Disposición de las juntas\r\n  1.2.5 Espigas a lo largo de las juntas\r\n1.3   Proceso\r\n  1.3.1 Tolerancias de la superficie de  la losa\r\n  1.3.2 Tolerancias de la superficie de  la losa\r\n  1.3.3 Camas de arena\r\n2. EL SISTEMA DE CIMENTACIÓN\r\n2.1   Cimentación interior\r\n2.2   Cimentación perimetral\r\n  2.2.1  Zapatas continúas\r\n  2.2.2  Zapatas cargadas excéntricamente\r\n  2.2.3  Vigas de nivel\r\n  2.2.4  Zapatas aisladas\r\n  2.2.5  Cimentación de muro\r\n  2.2.6  Cimentación profunda\r\n2.3   Casos específicos\r\n2.4   Almohadillas de montaje de paneles\r\n  2.4.1  Almohadillas de montaje de lechada\r\n  2.4.2  Almohadillas de soporte de plástico\r\n3. DISPOSICIÓN Y MOLDAJE DE PANELES\r\n3.1   Componentes de moldaje\r\n3.2   Características del panel de moldaje\r\n3.3   Acabados arquitectónicos de moldaje\r\n  3.3.1 Ladrillo delgado\r\n  3.3.2 Textura de hoyuelos\r\n3.4    Proceso de moldaje\r\n  3.4.1 Tratamiento de las juntas de las losas\r\n  3.4.2 Disposición de moldaje\r\n  3.4.3 Moldaje de paneles curvados\r\n  3.4.4 Moldaje de paneles emparedados\r\n  3.4.5 Moldaje de colado apilado\r\n3.5   Sujeción de los moldes\r\n  3.5.1 Sujeción mecánica\r\n  3.5.2 Sistemas adhesivos\r\n3.6   Sellado de los moldes\r\n3.7   Aplicación de la liberación de adhesivos\r\n4. REFUERZOS, INSERTOS Y EMPOTRAMIENTOS\r\n4.1   Refuerzo de paneles\r\n4.2   Colocación\r\n4.3   Contaminantes\r\n4.4   Elementos empotrados\r\n  4.4.1  Insertos de levantamiento\r\n  4.4.2  Insertos de arriostramiento\r\n4.5   Piezas empotradas estructurales\r\n4.6   Barras de cuerda\r\n',	'https://grabador.imcyc.com/Imagenes/generated_images/Modulo2.jpeg',	0,	0,	'2025-11-06 15:04:29',	'2026-02-13 16:59:20'),
('modulo-3',	3,	'Modulo 3',	'Proceso completo de levantamiento de paneles Tilt-Up, instalación y acabados finales. Aprende sobre grúas, conexiones estructurales y detalles arquitectónicos.',	'Aprende el proceso completo de levantamiento y acabado de estructuras Tilt-Up:\r\n\r\n• Preparación de paneles prefabricados\r\n• Técnicas de izado con grúas especializadas\r\n• Sistemas de apuntalamiento temporal\r\n• Conexiones estructurales entre paneles\r\n• Sellado de juntas y acabados\r\n• Instalación de sistemas de fachada\r\n• Acabados arquitectónicos exteriores\r\n• Revestimientos y tratamientos superficiales\r\n• Control de calidad final\r\n\r\nProcesos de levantamiento:\r\n- Planificación logística del izado\r\n- Coordinación con operadores de grúa\r\n- Seguridad en operaciones de altura\r\n- Secuencia óptima de instalación\r\n- Ajustes y alineación de paneles\r\n\r\nAcabados especializados:\r\n- Texturas arquitectónicas en concreto\r\n- Tratamientos de color y pigmentación\r\n- Aislamiento térmico y acústico\r\n- Sistemas de impermeabilización\r\n- Instalación de ventanas y aberturas\r\n\r\nDuración estimada: 12 horas de estudio',	'https://grabador.imcyc.com/Imagenes/generated_images/Modulo3.jpeg',	0,	0,	'2025-11-06 15:04:29',	'2026-02-13 16:59:28'),
('modulo-4',	4,	'Modulo 4',	'Documentación técnica, reportes de obra y formatos de control de calidad. Gestión de proyectos y coordinación de equipos en campo.',	'',	'https://grabador.imcyc.com/Imagenes/generated_images/Modulo4.jpeg',	0,	0,	'2025-11-06 15:04:29',	'2026-02-13 16:59:35');
